    public static function find(?string $slug): ?array
    {
        if (!$slug) {
            return null;
        }

        $articles = self::all();
        return $articles[$slug] ?? null;
    }

    public static function toPlainText(array $article): string
    {
        $lines = [];

        if (!empty($article['lead'])) {
            $lines[] = $article['lead'];
            $lines[] = '';
        }

        $sections = $article['sections'] ?? [];
        if (count($sections)) {
            $lines[] = 'Pembahasan dalam artikel:';
            foreach ($sections as $section) {
                $lines[] = '- ' . ($section['title'] ?? 'Pembahasan');
            }
            $lines[] = '';
        }

        foreach ($sections as $section) {
            $lines[] = $section['title'] ?? 'Pembahasan';
            $body = $section['body'] ?? [];
            if (!is_array($body)) {
                $body = [$body];
            }
            foreach ($body as $paragraph) {
                $lines[] = $paragraph;
                $lines[] = '';
            }
        }

        if (!empty($article['tips']) && is_array($article['tips'])) {
            $lines[] = 'Catatan kecil sebelum membeli:';
            foreach ($article['tips'] as $tip) {
                $lines[] = '- ' . $tip;
            }
            $lines[] = '';
        }

        if (!empty($article['closing'])) {
            $lines[] = $article['closing'];
        }

        return trim(preg_replace("/\n{3,}/", "\n\n", implode("\n", $lines)));
    }
}
